+import { isRelation, isRelationPair } from '../relation/utils/is-relation';
+import type { Trait } from '../trait/types';
+import { $aspect } from './symbols';
+import type { Aspect, AspectInput } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return Boolean((value as Aspect | null | undefined)?.[$aspect]);
+}
+
+export function createAspect<const T extends readonly AspectInput[]>(...inputs: T): Aspect {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+
+    const add = (input: AspectInput) => {
+        if (isAspect(input)) {
+            for (const trait of input.traits) add(trait);
+            return;
+        }
+        if (isRelation(input) || isRelationPair(input) || input[$aspect as never]) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        for (const field of Object.keys(input.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: Aspect constituents cannot share the field "${field}".`);
+            }
+            fields.add(field);
+        }
+        traits.push(input);
+    };
+
+    for (const input of inputs) add(input);
+    if (traits.length < 2) throw new Error('Koota: An aspect requires at least two traits.');
+
+    const schema = Object.assign({}, ...traits.map((trait) => trait.schema));
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema });
+}
